def hex_to_rgb\(h\):
    h = h.lstrip\('#'\)
    return tuple\(int\(h[i:i+2], 16\) for i in \(0, 2, 4\)\)
def luminance\(rgb\):
    vals = []
    for c in rgb:
        c = c / 255.0
        c = c / 12.92 if c <= 0.03928 else \(\(c + 0.055\) / 1.055\) ** 2.4
        vals.append\(c\)
    return 0.2126 * vals[0] + 0.7152 * vals[1] + 0.0722 * vals[2]
def contrast\(c1, c2\):
    l1, l2 = luminance\(hex_to_rgb\(c1\)\), luminance\(hex_to_rgb\(c2\)\)
    return \(max\(l1,l2\)+0.05\) / \(min\(l1,l2\)+0.05\)

pairs = [
    \('Green text on white \(#1d8013\)', '#1d8013', '#ffffff'\),
    \('Green text on cream \(#1d8013\)', '#1d8013', '#f7f4ef'\),
    \('Text3 on white \(#666\)', '#666666', '#ffffff'\),
    \('White on green-bright bg', '#ffffff', '#36d022'\),
]
for name, fg, bg in pairs:
    r = contrast\(fg, bg\)
    status = 'PASS' if r >= 4.5 else 'FAIL'
    print\(f'  {r:.1f}:1 [{status}] {name}'\)
")

