    if not isinstance\(cat, dict\) or 'subcategories' not in cat:
        continue
    for sub_name, sub in cat['subcategories'].items\(\):
        if not isinstance\(sub, dict\) or 'products' not in sub:
            continue
        for prod_name, prod in sub['products'].items\(\):
            if isinstance\(prod, dict\) and 'file' in prod:
                product_files.append\(prod['file']\)

existing = [f for f in product_files if os.path.exists\(f\)]
missing = [f for f in product_files if not os.path.exists\(f\)]
print\(f'Existing: {len\(existing\)}, Missing: {len\(missing\)}'\)
print\('Missing files:'\)
for f in sorted\(missing\):
    print\(f'  {f}'\)
